  ('retired-7ec62a85-moex-00233', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '普通重型機車駕駛執照中，如附記「不得駕駛大型重型機車，違者依法論處」。則此一附記之法 律性質為何？ 非屬附款  附款之負擔  附款之停止條件  附款之解除條件', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00234', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '依訴願法得申請再審之事由中，下列何者之再審期間一律自訴願決定確定時起算？ 依法令應迴避之委員參與決定  訴願決定適用法規顯有錯誤 為決定基礎之證物，係偽造或變造者  訴願決定機關之組織不合法', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00235', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '人民與臺北市政府締結行政契約，因臺北市政府拒絕履行該契約之新臺幣40萬元金錢給付義務 而提起訴願，訴願管轄機關應如何處理？ 移送臺北地方法院審理，並通知訴願人  移送臺北高等行政法院審理，並通知訴願人 訴願無理由，以決定駁回之  為不受理之決定', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00236', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '關於行政訴訟「確認訴訟」類型之敘述，下列何者錯誤？ 行政處分已執行完畢而無法回復者，人民得提起確認行政處分違法之訴訟 行政訴訟之原告提起撤銷訴訟，於審理程序中，認為系爭行政處分應屬無效，得主張將其訴之 聲明轉換為確認系爭處分無效 原告得提起撤銷訴訟、課予義務訴訟或一般給付訴訟者，不得提起確認訴訟，即使確認行政處 分無效之訴訟亦同 行政訴訟類型並無確認行政處分有效之訴訟', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00237', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '關於交通裁決事件訴訟程序之敘述，下列何者錯誤？ 交通裁決事件訴訟之提起，應以原處分機關為被告，逕向管轄之地方法院行政訴訟庭為之 交通裁決事件之裁判，得不經言詞辯論為之 交通裁決事件中撤銷訴訟之提起，應於裁決書送達後40日之不變期間內為之 因訴之變更致其訴之一部，不屬於交通裁決事件之範圍者，地方法院行政訴訟庭應改依簡易訴 訟程序審理或移送管轄之高等行政法院', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00238', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '經濟部之公務員甲，於借調至文化部期間，因執行職務致生國家賠償責任時，應以何機關為賠償 義務機關？ 以甲之本職機關經濟部為賠償義務機關 以甲之借調機關文化部為賠償義務機關 以共同上級機關之行政院為賠償義務機關 基於連帶責任，以經濟部與文化部為共同賠償義務機關', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00239', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '有關損失補償與國家賠償制度之敘述，下列何者正確？ 損失補償與國家賠償均屬公法爭議，依法由普通法院民事庭管轄 國家給付人民補償或賠償後，均得對故意或重大過失之公務員行使求償權 人民因國家公權力合法行使而受有特別犧牲時，國家應負賠償責任 國家之損失補償責任不以公務員有故意或過失為要件', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00240', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-8d1d3a67', 'sub-retired-7ec62a85-05', NULL, 'essay', '甲於擔任司法警察期間，查獲乙入丙室竊取勞力士手錶乙只。案件移送
臺北地方檢察署後，乙因逃亡遭通緝，致該案偵查無法繼續進行。又因
甲先前通過司法官特考，於移送乙竊盜案後，旋即接受司法官學習訓練，
後分發至臺北地方檢察署擔任候補檢察官職位。甲擔任候補檢察官後，
乙經通緝到案，試問：甲得否於乙竊盜案之偵查程序執行職務？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "7c13bfbc5142", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0906", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00241', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-8d1d3a67', 'sub-retired-7ec62a85-05', NULL, 'essay', '甲涉犯刑法第 173 條第 1項放火罪，偵查中檢察官認其有逃亡與串證之
虞，向法院聲請羈押，惟甲並未委任辯護人到場。如於等候指定辯護人
逾四小時未到場，經被告主動請求訊問後，法院應依職權使被告獲知那
